```hcl
# Phase 1: COUNT mode
rule {
  name     = "query-string-too-large"
  priority = 40

  action {
    count {}
  }

  statement {
    size_constraint_statement {
      comparison_operator = "GT"
      size                = 2048 # tune between 1024-2048 based on baseline

      field_to_match {
        query_string {}
      }

      text_transformation {
        priority = 0
        type     = "NONE"
      }
    }
  }

  visibility_config {
    cloudwatch_metrics_enabled = true
    metric_name                = "queryStringTooLarge"
    sampled_requests_enabled   = true
  }
}

